import classes from "./ChatInput.module.css";

const ChatInput = () => {
  const onSubmitHandler = () => {
    console.log("HERE")
  }

  return (

    <form onSubmit={onSubmitHandler}>
      <div className={classes["container"]}>
        <div>+</div>
        <div
          contentEditable
          role="textbox"
          aria-label="Message"
          aria-multiline="true"
          className={classes["text-area"]}
        >
          Test
        </div>
      </div>
    </form>
  );
};

export default ChatInput;
